/**
 * Secret Handler — PostToolUse hook for Read/Bash/Grep/Glob outputs.
 * Issue #1543 (M126 Bundle C): adopts CC 2.1.121's
 * hookSpecificOutput.updatedToolOutput (extends 2.1.69's MCP-only
 * updatedMCPToolOutput to all tools).
 *
 * Three modes via ORK_SECRET_HOOK env var:
 *   OFF (default) — no-op; behavior-preserving rollout
 *   AUDIT         — sidecar log of would-be matches; output unchanged
 *   REDACT        — in-place [REDACTED:type] for bounded patterns;
 *                   gate (replace whole output) for critical patterns
 *
 * Pattern philosophy:
 *   - BOUNDED prefix patterns (gh*_, sk-*, AKIA*) — effectively zero FP rate.
 *     Safe to redact in place.
 *   - CRITICAL unbounded patterns (AWS secret 40-char base64, SSH/GPG private
 *     blocks) — collide with hashes/UUIDs. Gate the entire output instead.
 *
 * Backwards-compat: CC < 2.1.121 silently ignores updatedToolOutput
 * (was MCP-only). AUDIT logging still works on any CC.
 *
 * Implementation split across ./secret-handler/ subdir for line-cap budget:
 *   patterns.ts — BOUNDED + CRITICAL pattern arrays + tool guard set
 *   detect.ts   — pure detection + redaction + stringify helpers
 *   audit.ts    — sidecar log writer + Mode resolver + gate message
 */

import type { HookInput, HookResult, HookMeta, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import { PROCESSED_TOOLS } from './secret-handler/patterns.js';
import { detect, applyRedactions, hashSpans, stringifyOutput } from './secret-handler/detect.js';
import { type AuditEntry, getMode, logAudit, gateMessage } from './secret-handler/audit.js';

export const meta: HookMeta = {
  name: 'posttool/secret-handler',
  description:
    'Detects API keys + private blocks in Read/Bash/Grep/Glob output. ' +
    'OFF (default) | AUDIT | REDACT via ORK_SECRET_HOOK env var (#1543).',
  event: 'PostToolUse',
  matchers: ['Read', 'Bash', 'Grep', 'Glob'],
  tier: 'standard',
  timeout: 5,
};

export function secretHandler(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const mode = getMode();
  if (mode === 'OFF') return outputSilentSuccess();

  const toolName = input.tool_name || '';
  if (!PROCESSED_TOOLS.has(toolName)) return outputSilentSuccess();

  const rawOutput = input.tool_output ?? input.tool_result;
  const outputStr = stringifyOutput(rawOutput);
  if (!outputStr || outputStr.length === 0) return outputSilentSuccess();

  const detection = detect(outputStr);
  if (!detection.anyHit) return outputSilentSuccess();

  const sessionId = input.session_id || '';
  const timestamp = new Date().toISOString();

  // AUDIT mode: log every hit; mutate nothing
  if (mode === 'AUDIT') {
    if (detection.criticalHit) {
      const e: AuditEntry = {
        timestamp,
        tool: toolName,
        session_id: sessionId,
        mode,
        action: 'audit',
        pattern_name: detection.criticalHit.name,
        match_count: 1,
        span_hash: hashSpans([detection.criticalHit.description]),
        span_length: 0,
      };
      logAudit(e);
    }
    for (const h of detection.boundedHits) {
      const e: AuditEntry = {
        timestamp,
        tool: toolName,
        session_id: sessionId,
        mode,
        action: 'audit',
        pattern_name: h.pattern.name,
        match_count: h.matches.length,
        span_hash: hashSpans(h.matches),
        span_length: h.matches.reduce((s, m) => s + m.length, 0),
      };
      logAudit(e);
    }
    ctx.log(
      'secret-handler',
      `AUDIT: ${toolName} → ${detection.boundedHits.length} bounded + ${detection.criticalHit ? 1 : 0} critical`,
      'info',
    );
    return outputSilentSuccess();
  }

  // REDACT mode
  let finalOutput: string;
  let action: 'redact' | 'gate';
  let logName: string;

  if (detection.criticalHit) {
    finalOutput = gateMessage(detection.criticalHit.name);
    action = 'gate';
    logName = detection.criticalHit.name;
    logAudit({
      timestamp,
      tool: toolName,
      session_id: sessionId,
      mode,
      action: 'gate',
      pattern_name: detection.criticalHit.name,
      match_count: 1,
      span_hash: hashSpans([detection.criticalHit.description]),
      span_length: 0,
    });
  } else {
    finalOutput = applyRedactions(outputStr, detection.boundedHits);
    action = 'redact';
    logName = detection.boundedHits.map((h) => h.pattern.name).join(',');
    for (const h of detection.boundedHits) {
      logAudit({
        timestamp,
        tool: toolName,
        session_id: sessionId,
        mode,
        action: 'redact',
        pattern_name: h.pattern.name,
        match_count: h.matches.length,
        span_hash: hashSpans(h.matches),
        span_length: h.matches.reduce((s, m) => s + m.length, 0),
      });
    }
  }

  ctx.log('secret-handler', `REDACT: ${toolName} → ${action} (${logName})`, 'warn');

  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: {
      hookEventName: 'PostToolUse',
      updatedToolOutput: finalOutput,
    },
  };
}
